sql:
SELECT e.employee_name, eg.goal, eg.target_date, eg.status 
FROM employees e 
INNER JOIN employee_performance_goals eg ON e.employee_id = eg.employee_id;

SELECT COUNT(*) 
FROM employee_training 
WHERE program_id = (SELECT program_id FROM training_programs WHERE program_name = 'Communication Skills');

